print(f"{(time1 := input('Insira o nome do 1o time: ')) and ''}{(gols1 := int(input('Insira o número de gols marcados pelo 1o time: '))) and ''}{(time2 := input('Insira o nome do 2o time: ')) and ''}{(gols2 := int(input('Insira o número de gols marcados pelo 2o time: '))) and ''}{(f'O vencedor é {time1}.' if gols1 > gols2 else (f'O vencedor é {time2}.' if gols2 > gols1 else 'EMPATE.'))}")
